'use client';

import { cn } from '@/lib/utils';
import './style.css';

/*
 * @author: @joao-carmassi
 * @description: Animated shining radial-gradient border effect.
 * Drop <ShineBorder /> inside any Card (with `relative` on the Card).
 * @version: 1.0.0
 * @date: 2026-24-03
 * @license: MIT
 * @reference: https://magicui.design/docs/components/shine-border
 */

interface ShineBorderProps extends React.HTMLAttributes<HTMLDivElement> {
  /**
   * Width of the border in pixels
   * @default 1
   */
  borderWidth?: number;
  /**
   * Duration of the animation in seconds
   * @default 14
   */
  duration?: number;
  /**
   * Color of the border, can be a single color or an array of colors
   * @default "#000000"
   */
  shineColor?: string | string[];
}

/**
 * Shine Border
 *
 * An animated background border effect component with configurable properties.
 */
export function ShineBorder({
  borderWidth = 1,
  duration = 14,
  shineColor = '#000000',
  className,
  style,
  ...props
}: ShineBorderProps) {
  return (
    <div
      style={
        {
          '--border-width': `${borderWidth}px`,
          '--duration': `${duration}s`,
          backgroundImage: `radial-gradient(transparent,transparent, ${
            Array.isArray(shineColor) ? shineColor.join(',') : shineColor
          },transparent,transparent)`,
          backgroundSize: '300% 300%',
          mask: `linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0)`,
          WebkitMask: `linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0)`,
          WebkitMaskComposite: 'xor',
          maskComposite: 'exclude',
          padding: 'var(--border-width)',
          ...style,
        } as React.CSSProperties
      }
      className={cn(
        'card-shine-effect pointer-events-none absolute inset-0 size-full rounded-[inherit] will-change-[background-position]',
        className,
      )}
      {...props}
    />
  );
}

[data-variant='default'] {
  --pulse-color: var(--primary);
}
[data-variant='destructive'] {
  --pulse-color: var(--destructive);
}
[data-variant='secondary'] {
  --pulse-color: var(--secondary-foreground);
}
[data-variant='outline'] {
  --pulse-color: var(--ring);
}
[data-variant='ghost'] {
  --pulse-color: var(--ring);
}

.before\:animate-shine-effect::before {
  animation: shine-effect 3s ease-out infinite;
}

.animate-rainbow-effect {
  animation: rainbow-effect 3s linear infinite;
}

.animate-pulsating-effect {
  animation: pulsating-effect 1.5s ease-out infinite;
}

.card-shine-effect {
  animation: card-shine-effect var(--duration) infinite linear;
}

@keyframes shine-effect {
  0% {
    background-position: 200% 0;
  }
  25% {
    background-position: -200% 0;
  }
  100% {
    background-position: -200% 0;
  }
}

@keyframes rainbow-effect {
  0% {
    background-position: 0%;
  }
  100% {
    background-position: 200%;
  }
}

@keyframes pulsating-effect {
  0% {
    box-shadow: 0 0 0 0 var(--pulse-color, currentColor);
  }
  70% {
    box-shadow: 0 0 0 8px transparent;
  }
  100% {
    box-shadow: 0 0 0 0 transparent;
  }
}

@keyframes card-shine-effect {
  0% {
    background-position: 0% 0%;
  }
  50% {
    background-position: 100% 100%;
  }
  to {
    background-position: 0% 0%;
  }
}
